output-schema.json-structure:
{
  "intro": "string (total opportunity summary)",
  "quickWins": [
    {
      "title": "string (keyword or tactic)",
      "description": "string (1-2 sentences)",
      "impact": "string (estimated traffic/value)"
    }
  ],
  "mediumTerm": [
    {
      "title": "string",
      "description": "string",
      "impact": "string"
    }
  ],
  "longTerm": [
    {
      "title": "string",
      "description": "string",
      "impact": "string"
    }
  ]
}

examples.example:
{
  "intro": "Identifikavome 47 raktazodzius su bendru 15,000 menesiniiu paieskiu potencialu. Prioritetizuojame pagal sunkuma ir srautu verte.",
  "quickWins": [
    {
      "title": "Optimizuoti 'plauku priziura vasarai'",
      "description": "Jau esate 14 pozicijoje. Su meta optimizacija ir turinio papildymu galite pasiekti TOP 5.",
      "impact": "+300 lankytoju/men. (~€600 verte)"
    }
  ],
  "mediumTerm": [
    {
      "title": "Sukurti straipsniu serija apie plauku tipus",
      "description": "5 raktazodziai su bendru 2,000 menesiniiu paieskiu. Turinys pozicionuoja jus kaip eksperta.",
      "impact": "+800 lankytoju/men. per 3 men."
    }
  ],
  "longTerm": [
    {
      "title": "Konkuruoti del 'plauku kirpykla vilnius'",
      "description": "Auksto sunkumo raktazodis (KD: 62), bet labai vertunga. Reikalauja nuorodu strategijos.",
      "impact": "+1,500 lankytoju/men. per 6-9 men."
    }
  ]
}
